// Build an HTML digest table from the aggregated rows
const rows = $input.all().map(i => i.json);
const tr = rows.map(r =>
  `<tr><td>${r.reportId ?? ''}</td><td>${r.kpi ?? ''}</td><td>${r.count ?? 1}</td></tr>`
).join('');
const html = `<h2>Metric digest</h2><table border="1" cellpadding="4">
<tr><th>ID</th><th>kpi</th><th>Count</th></tr>${tr}</table>`;
return [{ json: { html, rowCount: rows.length, generatedAt: new Date().toISOString() } }];
